-- ГОРЯЧИЕ ИСТОЧНИКИ ЮГА КАМЧАТКИ (у вулкана Кошелевский)
-- ══════════════════════════════════════════════════════════════

UPDATE agent_route_knowledge SET updated_at = NOW(), description =
'Верхне-Кошелевские парогидротермальные источники — паровые поля на склоне вулкана Кошелевский (51.46°N, 156.80°E). Температура пара до 97–100°C. Кислые сульфатно-хлоридные воды pH 2–3, содержат H₂S, SO₂, HCl. Пейзаж лунный: жёлтые серные отложения, паровые столбы, бурлящие котлы. Добраться только вертолётом в рамках южно-камчатских туров. Купаться нельзя — слишком кислые и горячие.'
WHERE id = 'ceff740f-3b8e-4a7c-9d51-2f4c1e0b5a68';

UPDATE agent_route_knowledge SET updated_at = NOW(), description =
'Нижне-Кошелевские термальные источники (Гремучие ключи) — горячие источники у подножия вулкана Кошелевский (51.49°N, 156.50°E). Температура воды 54–65°C. Хлоридно-натриевые гидрокарбонатные воды, борные (B до 30 мг/л). Характерное «гремучее» — бурление и шум. Нижнее поле доступнее верхнего. Добраться только вертолётом или длинным пешим маршрутом по южной Камчатке. Нерест нерки рядом в реке.'
WHERE id = 'e698db3e-9c4f-4a7b-b362-1e5d2c0b8a73';

UPDATE agent_route_knowledge SET updated_at = NOW(), description =
'Ходуткинские термальные источники — горячие источники в долине реки Ходутка, Южная Камчатка (52.11°N, 157.66°E). Температура воды 42–44°C, идеальна для купания. Состав: кремнисто-борные — SiO₂ 90–120 мг/л, B до 40 мг/л. Ванны из природного камня. Лечебные свойства: кожные заболевания, суставы, нервная система. Рядом — медвежья тропа и нерест нерки. Только вертолётом или 3-дневным пешим маршрутом.'
WHERE id = '1b4c28d7-5e3a-4b9c-8f72-7d2c1e0b4a56';

UPDATE agent_route_knowledge SET updated_at = NOW(), description =
'Паужетские термальные источники — геотермальное поле у посёлка Паужетка (51.47°N, 156.81°E). Самая мощная геотермальная электростанция Камчатки работает на этих источниках с 1966 года (12 МВт). Температура в скважинах до 100°C. Хлоридно-натриевые борные воды (B до 100 мг/л). Для купания — остывшая вода в оборудованных ваннах (38–42°C). Лечение: ОДА, кожа, нервная система. Добраться через Озерновский.'
WHERE id = 'cb7a9232-4d7e-4a8c-b951-6f3c2e1a0b47';

