UPDATE agent_route_knowledge SET updated_at = NOW(), description =
'Начикинские термальные источники — курортная зона в долине реки Начика (53.12°N, 157.74°E). Температура воды 38–52°C. Состав: хлоридно-натриевые кремнистые, SiO₂ 50–70 мг/л, pH 7.2–7.5. Лечебные свойства: ОДА, гинекология, нервная система, кожные болезни. Оборудованные открытые и закрытые бассейны. Добраться из Петропавловска 2,5 часа на машине. Популярное место отдыха.'
WHERE id = '68cfb671-8f5c-4a7e-b493-2d1c3e0b9a54';

UPDATE agent_route_knowledge SET updated_at = NOW(), description =
'Большие Банные термальные источники — горячие источники в горах к западу от Петропавловска (53.02°N, 157.79°E). Температура воды 45–60°C. Хлоридно-натриевые щелочные воды. Исторически первое место купания для жителей Петропавловска — отсюда название «Банные». Несколько выходов термальной воды вдоль ручья. Дикое место без инфраструктуры. Добраться по грунтовой дороге ~3 часа.'
WHERE id = '967fa0a7-2c8f-4e5b-9d71-4a3c1e0b6f82';

UPDATE agent_route_knowledge SET updated_at = NOW(), description =
'Карымшинские термальные источники — горячие источники близ посёлка Карымши в центральной Камчатке (~52.8°N, 157.5°E). Температура воды 40–50°C. Хлоридно-натриевые воды с кремнием. Оборудованные деревянные ванны с термальной водой. Красивое место в долине реки. Нерест лосося осенью. Добраться по грунтовке из Петропавловска ~4 часа.'
WHERE id = 'b2a206bc-6e9a-4f3c-b841-5d7c2e1a0b36';

