UPDATE agent_route_knowledge SET updated_at = NOW(), description =
'Быстринские термальные источники (47-й км) — горячие источники вдоль дороги Эссо–Анавгай, 47-й километр (56.02°N, 159.09°E). Температура 38–45°C. Хлоридно-натриевые гидрокарбонатные воды с кремнием. Несложный доступ: прямо у трассы. Небольшие бассейны под открытым небом. Остановка для туристов на пути в Эссо или в горы. Круглогодичный доступ, зимой особенно эффектно — пар над водой в морозный день.'
WHERE id = 'a49536e5-3d8f-4c7b-9a52-1e6c2e0b4a71';

UPDATE agent_route_knowledge SET updated_at = NOW(), description =
'Эссовские (Уксичанские) термальные источники — горячие источники у посёлка Эссо в Быстринском парке (55.93°N, 158.70°E). Температура воды 38–42°C. Гидрокарбонатно-натриевые кремниевые воды (SiO₂ 60–90 мг/л), pH 8.0–8.5. Питают открытый термальный бассейн Эссо — главную достопримечательность посёлка. Лечебные свойства: ОДА, нервная система, кожа. Добраться из ПК 6–7 часов на машине.'
WHERE id = '3c15b2d2-7a9e-4c5f-b841-4d3c2e1a0b67';

